refsection.programlisting:
mask = zeros(140, 230) == 1;
mask(25:75, 25:75) = %t;
mask(25:105, 145:165) = %t;
mask(85:105, 145:205) = %t;

startPoint = [190 95];
boundary = imbwtraceboundary(mask, startPoint, 8);
closedBoundary = [boundary; boundary(1, :)];
plotBoundary = rect2cart(size(mask), closedBoundary);
plotSeed = rect2cart(size(mask), startPoint);

imshow(uint8(mask .* 255));
axesHandle = gca();
axesHandle.auto_clear = "off";
plot(plotBoundary(:, 1), plotBoundary(:, 2), "r-");
plot(plotSeed(1), plotSeed(2), "g+");
xtitle("The seed selects the L-shaped component");

image = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
gray = rgb2gray(image);
mask = gray < 230;

startPoint = [205 210];
boundary = imbwtraceboundary(mask, startPoint);
closedBoundary = [boundary; boundary(1, :)];
plotBoundary = rect2cart(size(mask), closedBoundary);
plotSeed = rect2cart(size(mask), startPoint);

imshow(image);
axesHandle = gca();
axesHandle.auto_clear = "off";
plot(plotBoundary(:, 1), plotBoundary(:, 2), "r-");
plot(plotSeed(1), plotSeed(2), "g+");
xtitle("Boundary of the orange Smartie nearest to the seed");
